import 'package:bookly/Features/Home/Data/Repos/home_repo.dart';import 'package:flutter/material.dart';import 'package:flutter_bloc/flutter_bloc.dart';import '../../Data/model/book_model.dart';part 'novels_book_state.dart';class NovelsBooksCubit extends Cubit<NovelsBooksState> {  NovelsBooksCubit(this.homeRepo) : super(NovelsBooksInitial());  static NovelsBooksCubit get(context) => BlocProvider.of(context);  final HomeRepo homeRepo;  Future<void> fetchNewsBooksBooks() async {    emit(NovelsBooksLoading());    var result = await homeRepo.fetchNewsBooksNovels();    result.fold((failure) {      emit(NovelsBooksFailure(error: failure.errMessage));    },        (books) {      emit(NovelsBooksSuccess(books: books));    });  }}